                        >
                            {isDemoMode ? '下一步：Demo 生成' : '下一步：AI 生成 (消耗 1 配額)'}
                        </button>
                  </div>
               </div>

               <div className="mt-8">
                   <div className="flex items-center justify-between mb-4">
