            ...logData,
            // Truncate result to save space
            res: logData.res ? logData.res.substring(0, 500) : '',
            ts: Date.now()
        };

        if (!isMock) {
            // Use 'add' to auto-generate ID
            await db.collection('usage_logs').add(log);
        } else {
            console.log("[Mock Log]", log);
        }
    } catch (e) {
        // Fail silently - logging should not break app
        console.warn("Logging failed", e);
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, CtaItem } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota, getSystemConfig, logUserActivity } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
}

// --- New Component: Enhanced Loading Overlay ---
