            const logs = await getUserUsageLogs(targetUserId);

            if (logs.length === 0) {
                alert("該用戶尚無使用紀錄可供下載。");
                setLoading(false);
                return;
            }

            // Convert to CSV
            // BOM for Excel Chinese support
            let csvContent = "\uFEFFTimeStamp,Action,Topic,Prompt,Result(Truncated),Params\n";

            logs.forEach(log => {
                const ts = new Date(log.ts).toLocaleString().replace(/,/g, ' ');
