            }
        });
    } else {
        // Mock Subscription
        const check = () => {
             const uid = localStorage.getItem(SESSION_KEY);
             if(uid) {
                 const users = getDb(DB_USERS);
                 const u = users[uid];
                 const email = u ? u.email : 'demo@example.com';
