                                                title="手動修改"
                                            >
                                                ✎
                                            </button>
                                        </div>
                                    )}
                                </td>
                                <td className="p-4 text-xs text-gray-400">
                                   {user.unlockedFeatures && user.unlockedFeatures.length > 0 
                                      ? user.unlockedFeatures.join(', ') 
                                      : '-'}
