                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
      )}

      {/* VIEW: SYSTEM */}
      {activeTab === 'system' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-6">
                  <div className="bg-card p-6 rounded-xl border border-gray-700">
                      <h3 className="text-xl font-bold text-white mb-4">🔧 系統全域設定</h3>

                      <div className="space-y-4">
                          <div className="flex items-center justify-between p-4 bg-dark rounded border border-gray-600">
                              <div>
                                  <div className="font-bold text-white">🧪 Dry Run 模擬模式</div>
                                  <div className="text-xs text-gray-400">開啟後，所有 AI 生成與發文皆為模擬，不扣除真實配額，不連接外部 API。</div>
                              </div>
                              <button 
                                onClick={toggleDryRun}
                                className={`w-12 h-6 rounded-full transition-colors relative ${config.dryRunMode ? 'bg-yellow-500' : 'bg-gray-600'}`}
                              >
                                  <div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${config.dryRunMode ? 'translate-x-6' : ''}`}></div>
                              </button>
                          </div>

                          <div className="flex items-center justify-between p-4 bg-dark rounded border border-gray-600">
                              <div>
                                  <div className="font-bold text-white">🚧 系統維護模式</div>
                                  <div className="text-xs text-gray-400">開啟後，除管理員外，一般用戶將無法登入系統。</div>
                              </div>
                              <button 
                                onClick={toggleMaintenance}
                                className={`w-12 h-6 rounded-full transition-colors relative ${config.maintenanceMode ? 'bg-red-500' : 'bg-gray-600'}`}
                              >
                                  <div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${config.maintenanceMode ? 'translate-x-6' : ''}`}></div>
                              </button>
                          </div>
                      </div>
                  </div>
              </div>

              <div className="bg-card p-6 rounded-xl border border-gray-700 flex flex-col h-[500px]">
                  <div className="flex justify-between items-center mb-4">
                      <h3 className="text-xl font-bold text-white">📜 完整錯誤日誌</h3>
                      <button onClick={loadAllData} className="text-sm text-primary hover:underline">刷新</button>
                  </div>
                  <div className="flex-1 overflow-y-auto bg-dark p-2 rounded border border-gray-800 font-mono text-xs">
                      {logs.map(log => (
                          <div key={log.id} className="mb-2 pb-2 border-b border-gray-800 last:border-0">
                              <div className="flex gap-2 mb-1">
                                  <span className="text-gray-500">{new Date(log.timestamp).toLocaleString()}</span>
                                  <span className={`font-bold ${log.status === 'error' ? 'text-red-500' : log.status === 'warning' ? 'text-yellow-500' : 'text-green-500'}`}>
                                      {log.status.toUpperCase()}]
                                  </span>
                                  <span className="text-blue-400">{log.action}</span>
                              </div>
                              <div className="text-gray-300 pl-4 border-l-2 border-gray-700">
                                  User: {log.userEmail} <br/>
                                  Details: {log.details}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Security Action Modal (Download/Delete) */}
      {securityTarget && (
          <SecurityActionModal 
              targetUserId={securityTarget.uid} 
              actionType={securityTarget.type}
              onClose={() => setSecurityTarget(null)} 
          />
      )}
    </div>
  );
};

export default AdminPanel;

// ==========================================
// Core & API Types
// ==========================================

export interface ApiResponse<T = any> {
  success: boolean;
  data?: T;
  error?: {
    code: ErrorCode;
    message: string;
    details?: any;
  };
  timestamp: number;
}

export enum ErrorCode {
  // Auth
  UNAUTHORIZED = 'AUTH_001',
  FORBIDDEN = 'AUTH_002',
  TOKEN_EXPIRED = 'AUTH_003',

  // Resources
  NOT_FOUND = 'RES_001',
  VALIDATION_ERROR = 'RES_002',

  // Business Logic
  QUOTA_EXCEEDED = 'BIZ_001',
  FEATURE_LOCKED = 'BIZ_002',

  // External APIs
  FACEBOOK_API_ERROR = 'EXT_FB_001',
  AI_API_ERROR = 'EXT_AI_001',

  // System
  INTERNAL_ERROR = 'SYS_001',
  MAINTENANCE_MODE = 'SYS_002'
}

// ==========================================
// Domain: User & Membership
// ==========================================

// Tier Structure:
// user (Free): 10 Credits. FB Text Only.
// starter: 500 Credits. FB Schedule, AI Image, Basic Analytics.
// pro: 2000 Credits. Threads Nurture, SEO, Adv Analytics.
// business: 5000+ Credits. AutoPilot, Multi-Account.
// admin: Unlimited.
export type UserRole = 'user' | 'starter' | 'pro' | 'business' | 'admin';

export interface UserProfile {
  user_id: string;
  email: string;
  role: UserRole;
  // Use flat properties to match authService implementation
  quota_total: number;
  quota_used: number;
  quota_reset_date: number; // Timestamp

  isSuspended: boolean;
  unlockedFeatures: string[]; 

  // Referral System
  referralCode?: string; // My code to invite others
  referredBy?: string;   // Who invited me
  referralCount?: number;

  created_at: number;
  updated_at: number;
}

// ==========================================
// Domain: Usage Logging (New)
// ==========================================

export interface UsageLog {
  uid: string;           // User ID
  act: 'draft' | 'img' | 'seo' | 'threads'; // Short action code
  topic: string;         // Main topic/keyword
  prmt: string;          // The Prompt (Full)
  res: string;           // Result (Truncated to 500 chars)
  params?: string;       // JSON string of settings (e.g., tone, style) - kept small
  ts: number;            // Timestamp
}

// ==========================================
// Domain: Brand & Settings
// ==========================================

export interface ReferenceFile {
  name: string;
  content: string;
}

export interface ThreadsAccount {
  id: string;
  username: string; // Friendly name for UI
  userId: string;   // Threads User ID
  token: string;    // Threads Access Token
  isActive: boolean;
