        if (doc.exists) {
            const data = doc.data() as CachedTrendData;
            const age = Date.now() - data.createdAt;
            if (age < CACHE_TTL && data.topics && data.topics.length > 0) {
                console.log(`[TrendCache] Hit: ${cacheId}`);
                return shuffleArray(data.topics);
